<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { ElMessage, ElMessageBox } from 'element-plus'; import PageState from '../components/PageState.vue'; import RiskBadge from '../components/RiskBadge.vue'; import { api } from '../services/api'; import { useResource } from '../composables/useResource'; import { useAuthStore } from '../stores/auth'
type RiskCase=Record<string,any>; const auth=useAuthStore(); const status=ref('OPEN'); const resource=useResource(()=>api<RiskCase[]>(`/api/v1/cases${status.value?`?status=${status.value}`:''}`))
async function claim(row:RiskCase){await api(`/api/v1/cases/${row.case_id}/claim`,{method:'POST'});ElMessage.success('案件已认领');resource.load()}
async function resolve(row:RiskCase){const {value}=await ElMessageBox.prompt('输入结论依据','结案',{inputPattern:/.{3,}/,inputErrorMessage:'请填写依据'});const label=await ElMessageBox.confirm('确认为欺诈？选择取消将标记为正常。','标签回流',{confirmButtonText:'欺诈',cancelButtonText:'正常',distinguishCancelAndClose:true}).then(()=> 'FRAUD').catch((action)=>{if(action==='cancel')return 'NORMAL';throw action});await api(`/api/v1/cases/${row.case_id}/resolve`,{method:'POST',body:JSON.stringify({label,reason:value})});ElMessage.success('案件已结案并回流训练标签');resource.load()}
onMounted(resource.load)
</script>
<template><div><header class="page-title"><div><h2>案件中心</h2><p>风险复核、协作记录与权威标签回流</p></div></header><article class="panel"><div class="toolbar"><el-radio-group v-model="status" @change="resource.load"><el-radio-button value="OPEN">待认领</el-radio-button><el-radio-button value="CLAIMED">处理中</el-radio-button><el-radio-button value="RESOLVED">已结案</el-radio-button></el-radio-group></div><PageState :loading="resource.loading.value" :error="resource.error.value" :empty="resource.data.value?.length===0" empty-text="当前队列已清空" @retry="resource.load"><el-table v-if="resource.data.value" :data="resource.data.value"><el-table-column prop="case_id" label="案件编号" min-width="170"><template #default="scope"><span class="mono">{{ scope.row.case_id }}</span></template></el-table-column><el-table-column prop="txn_id" label="交易流水"/><el-table-column label="风险"><template #default="scope"><RiskBadge :level="scope.row.risk_level"/></template></el-table-column><el-table-column prop="status" label="状态"/><el-table-column prop="assignee" label="处理人"/><el-table-column label="操作" width="190"><template #default="scope"><el-button v-if="scope.row.status==='OPEN'&&auth.can('case.write')" link type="primary" @click="claim(scope.row)">认领</el-button><el-button v-if="scope.row.status==='CLAIMED'&&auth.can('case.write')" link type="warning" @click="resolve(scope.row)">结案</el-button></template></el-table-column></el-table></PageState></article></div></template>
